/* CONFIG -------------------------------------------------------- */
const KEY_SITES  = "checksy-sites-v1";
const KEY_POPUP  = "checksy-popup-seen";

const CATEGORY_ORDER = ["video", "social", "funding", "portfolio"];

const DEFAULT_SITES = [
  { id: "youtube", name: "YouTube", icon: "youtube", url: "https://www.youtube.com/%S", enabled: true,  category: "video" },
  { id: "tiktok", name: "TikTok", icon: "tiktok", url: "https://www.tiktok.com/@%S", enabled: true,  category: "video" },
  { id: "twitch", name: "Twitch", icon: "twitch", url: "https://www.twitch.tv/%S", enabled: false, category: "video" },
  { id: "kick", name: "Kick", icon: "kick", url: "https://kick.com/%S", enabled: false, category: "video" },
  { id: "vimeo", name: "Vimeo", icon: "vimeo", url: "https://vimeo.com/%S", enabled: false, category: "video" },
  { id: "dailymotion", name: "Dailymotion", icon: "dailymotion", url: "https://www.dailymotion.com/%S", enabled: false, category: "video" },

  { id: "instagram", name: "Instagram", icon: "instagram", url: "https://www.instagram.com/%S", enabled: true,  category: "social" },
  { id: "twitter", name: "X (Twitter)", icon: "twitter", url: "https://x.com/%S", enabled: true,  category: "social" },
  { id: "threads", name: "Threads", icon: "threads", url: "https://www.threads.net/@%S", enabled: false, category: "social" },
  { id: "reddit", name: "Reddit", icon: "reddit", url: "https://www.reddit.com/user/%S", enabled: false, category: "social" },
  { id: "bsky", name: "Bluesky (search)", icon: "bsky", url: "https://bsky.app/search?q=%S", enabled: false, category: "social" },

  { id: "patreon", name: "Patreon", icon: "patreon", url: "https://www.patreon.com/%S", enabled: true,  category: "funding" },
  { id: "kofi", name: "Ko-fi", icon: "kofi", url: "https://ko-fi.com/%S", enabled: true,  category: "funding" },
  { id: "buymeacoffee", name: "Buy Me a Coffee", icon: "buymeacoffee", url: "https://www.buymeacoffee.com/%S", enabled: false, category: "funding" },
  { id: "gumroad", name: "Gumroad", icon: "gumroad", url: "https://%S.gumroad.com", enabled: false, category: "funding" },
  { id: "substack", name: "Substack", icon: "substack", url: "https://%S.substack.com", enabled: false, category: "funding" },

  { id: "behance", name: "Behance", icon: "behance", url: "https://www.behance.net/%S", enabled: false, category: "portfolio" },
  { id: "deviantart", name: "DeviantArt", icon: "deviantart", url: "https://www.deviantart.com/%S", enabled: false, category: "portfolio" },
  { id: "pinterest", name: "Pinterest", icon: "pinterest", url: "https://www.pinterest.com/%S", enabled: false, category: "portfolio" },
  { id: "flickr", name: "Flickr", icon: "flickr", url: "https://www.flickr.com/people/%S", enabled: false, category: "portfolio" }
];

/* STATE --------------------------------------------------------- */
let sites = loadSites();

/* DOM REFERENCES ------------------------------------------------ */
const handleInput     = document.getElementById("handle");
const btnCheck        = document.getElementById("btnCheck");
const groupsContainer = document.getElementById("groupsContainer");
const enabledCountEl  = document.getElementById("enabledCount");
const popupStrip      = document.getElementById("popupStrip");
const popupDismiss    = document.getElementById("popupDismiss");
const btnClear        = document.getElementById("btnClear");
const helpPopupTrigger = document.getElementById("helpPopupTrigger");
const helpBackdrop     = document.getElementById("help-backdrop");
const helpClose        = document.getElementById("help-close");

/* STORAGE ------------------------------------------------------- */
function cloneDefaultSites() {
  return JSON.parse(JSON.stringify(DEFAULT_SITES));
}

function loadSites() {
  try {
    const raw = localStorage.getItem(KEY_SITES);
    if (!raw) return cloneDefaultSites();
    const parsed = JSON.parse(raw);
    if (!Array.isArray(parsed) || !parsed.length) {
      return cloneDefaultSites();
    }
    return parsed.map(def => {
      const fallback = DEFAULT_SITES.find(d => d.id === def.id) || {};
      const merged = { ...fallback, ...def };
      merged.icon = def.icon || fallback.icon || def.id;
      merged.category = def.category || fallback.category || "other";
      return merged;
    });
  } catch (err) {
    console.warn("Checksy: failed to load sites, using defaults", err);
    return cloneDefaultSites();
  }
}

function saveSites() {
  try {
    localStorage.setItem(KEY_SITES, JSON.stringify(sites));
  } catch (err) {
    console.warn("Checksy: failed to save sites", err);
  }
}

/* UI ------------------------------------------------------------ */
function updateEnabledLabel() {
  const total = sites.length;
  const on = sites.filter(s => s.enabled).length;
  enabledCountEl.textContent = `${on} / ${total} sites enabled.`;
  btnCheck.disabled = on === 0;
}

const CATEGORY_TITLES = {
  video: "Video & streaming",
  social: "Social & community",
  funding: "Support & funding",
  portfolio: "Portfolios & assets"
};

function renderChips() {
  groupsContainer.innerHTML = "";

  const byCategory = {};
  sites.forEach(site => {
    const cat = site.category || "other";
    if (!byCategory[cat]) byCategory[cat] = [];
    byCategory[cat].push(site);
  });

  CATEGORY_ORDER.forEach(cat => {
    const items = byCategory[cat];
    if (!items || !items.length) return;

    const block = document.createElement("div");
    block.className = "group-block";

    const title = document.createElement("div");
    title.className = "group-title";
    title.textContent = CATEGORY_TITLES[cat] || cat;
    block.appendChild(title);

    const chipsRow = document.createElement("div");
    chipsRow.className = "chips";

    items.forEach(site => {
      const chip = document.createElement("button");
      chip.type = "button";
      chip.className = "chip " + (site.enabled ? "on" : "off");
      chip.dataset.siteId = site.id;

      const iconWrapper = document.createElement("span");
      iconWrapper.className = "chip-icon";
      const svgMarkup = ICONS[site.icon || site.id] || "";
      iconWrapper.innerHTML = svgMarkup;

      const label = document.createElement("span");
      label.textContent = site.name;

      chip.appendChild(iconWrapper);
      chip.appendChild(label);

      chip.addEventListener("click", () => toggleSite(site.id));

      chipsRow.appendChild(chip);
    });

    block.appendChild(chipsRow);
    groupsContainer.appendChild(block);
  });
}

function toggleSite(id) {
  const site = sites.find(s => s.id === id);
  if (!site) return;
  site.enabled = !site.enabled;
  saveSites();
  renderChips();
  updateEnabledLabel();
}

function deselectAllSites() {
  sites.forEach(s => { s.enabled = false; });
  saveSites();
  renderChips();
  updateEnabledLabel();
}

/* SEARCH LOGIC -------------------------------------------------- */
function normalizeHandle(raw) {
  return raw
    .trim()
    .toLowerCase()
    .replace(/\s+/g, "")
    .replace(/[^a-z0-9._-]/g, "");
}

function checkName() {
  const raw = handleInput.value;
  if (!raw.trim()) return;

  const slug = normalizeHandle(raw);
  if (!slug) {
    alert("Please use at least one letter or number in the name.");
    return;
  }

  const enabledSites = sites.filter(s => s.enabled);
  if (!enabledSites.length) {
    alert("No sites enabled.");
    return;
  }

  const encoded = encodeURIComponent(slug);
  enabledSites.forEach(site => {
    let url = site.url || "";
    if (url.includes("%S")) {
      url = url.replace(/%S/g, encoded);
    }
    window.open(url, "_blank");
  });
}

/* EVENT LISTENERS ----------------------------------------------- */
btnCheck.addEventListener("click", checkName);
handleInput.addEventListener("keydown", ev => {
  if (ev.key === "Enter") checkName();
});

btnClear.addEventListener("click", deselectAllSites);

popupDismiss.addEventListener("click", () => {
  popupStrip.style.display = "none";
  localStorage.setItem(KEY_POPUP, "1");
});

if (helpPopupTrigger && helpBackdrop && helpClose) {
  helpPopupTrigger.addEventListener("click", () => {
    helpBackdrop.classList.add("show");
  });

  helpClose.addEventListener("click", () => {
    helpBackdrop.classList.remove("show");
  });

  helpBackdrop.addEventListener("click", ev => {
    if (ev.target === helpBackdrop) {
      helpBackdrop.classList.remove("show");
    }
  });

  document.addEventListener("keydown", ev => {
    if (ev.key === "Escape") {
      helpBackdrop.classList.remove("show");
    }
  });
}

/* INIT ---------------------------------------------------------- */
renderChips();
updateEnabledLabel();

if (localStorage.getItem(KEY_POPUP) === "1") {
  popupStrip.style.display = "none";
}
